using System;
using System.Reflection;

using Microsoft.VisualStudio.TestTools.UnitTesting;

using Utils.Reflection.Reflection.Emit;

namespace UtilsTest.Reflection;

/// <summary>
/// Validates that <see cref="EmitWorkerProxy"/> can actually be generated by
/// <see cref="DispatchProxy.Create{TInterface, TProxy}"/> and that <c>Dispose</c> is intercepted
/// before a worker is attached — without starting a real isolated worker process.
/// </summary>
[TestClass]
public class EmitWorkerProxyTests
{
    public interface ITinyInterface : IDisposable
    {
        int Foo(int value);
    }

    [TestMethod]
    public void DispatchProxy_Create_ProducesAWorkingProxyInstance()
    {
        ITinyInterface proxy = DispatchProxy.Create<ITinyInterface, EmitWorkerProxy>();

        Assert.IsNotNull(proxy);
        Assert.IsInstanceOfType(proxy, typeof(EmitWorkerProxy));
    }

    [TestMethod]
    public void Invoke_BeforeWorkerIsAttached_ThrowsObjectDisposedException()
    {
        ITinyInterface proxy = DispatchProxy.Create<ITinyInterface, EmitWorkerProxy>();

        Assert.ThrowsException<ObjectDisposedException>(() => proxy.Foo(1));
    }

    [TestMethod]
    public void Dispose_BeforeWorkerIsAttached_DoesNotThrow()
    {
        ITinyInterface proxy = DispatchProxy.Create<ITinyInterface, EmitWorkerProxy>();

        // Dispose is special-cased in EmitWorkerProxy.Invoke and must be a safe no-op when no
        // worker was ever attached (for example if construction failed before AttachWorker ran).
        proxy.Dispose();
    }

    // ─── Item 49: invocation lease prevents concurrent disposal ──────────────────

    [TestMethod]
    public void Invoke_AfterDispose_ThrowsObjectDisposedException()
    {
        // Verify that after Dispose the read lock is immediately available but worker is null,
        // so subsequent calls throw ObjectDisposedException rather than silently using a dead worker.
        ITinyInterface proxy = DispatchProxy.Create<ITinyInterface, EmitWorkerProxy>();
        proxy.Dispose();

        Assert.ThrowsException<ObjectDisposedException>(() => proxy.Foo(1));
    }

    [TestMethod]
    public void Dispose_CalledTwice_DoesNotThrow()
    {
        ITinyInterface proxy = DispatchProxy.Create<ITinyInterface, EmitWorkerProxy>();
        proxy.Dispose();
        proxy.Dispose(); // Must be idempotent.
    }
}
